    /// Saves the current user preferences to the specified cache file.
    pub fn save(&self) -> io::Result<()> {
        let encoded = bincode::serialize(&self.preferences)
            .map_err(|e| io::Error::new(ErrorKind::Other, format!("Serialization error: {}", e)))?;

        fs::write(&self.cache_path, encoded)?;
        Ok(())
    }

    /// Loads user preferences from the specified cache file.
    /// If the file does not exist, a default cache is returned.
    /// If deserialization fails, an `io::Error` is returned.
    pub fn load(cache_path: impl Into<PathBuf>) -> io::Result<Self> {
        let path_buf = cache_path.into();
        match fs::read(&path_buf) {
            Ok(encoded) => {
                let preferences: UserPreferences = bincode::deserialize(&encoded)
                    .map_err(|e| io::Error::new(ErrorKind::InvalidData, format!("Deserialization error: {}", e)))?;
                Ok(Cache::new(preferences, path_buf))
            },
            Err(e) if e.kind() == ErrorKind::NotFound => {
                // If the cache file doesn't exist, create a default cache instance
                println!("Cache file not found at {:?}. Creating default preferences.", path_buf);
                let default_preferences = UserPreferences::default();
                let cache = Cache::new(default_preferences, path_buf);
                // Optionally save the default preferences immediately
                // cache.save()?;
                Ok(cache)
            },
            Err(e) => Err(e), // Other I/O errors
        }
    }
